// 获取文档段落总数及前20段内容预览
var doc = Application.ActiveDocument;
var sections = doc.Sections;
var totalParagraphs = 0;
var preview = [];

for (var i = 0; i < sections.Count; i++) {
    var section = sections.Item(i);
    var paragraphs = section.Paragraphs;
    totalParagraphs += paragraphs.Count;

    for (var j = 1; j <= Math.min(20, paragraphs.Count); j++) {
        var para = paragraphs.Item(j);
        var text = para.Range.Text;
        if (text && text.trim()) {
            preview.push({
                index: preview.length + 1,
                text: text.replace(/\r\n/g, '').replace(/\n/g, ''),
                hasList: para.ListFormat && para.ListFormat.ListType !== undefined
            });
        }
    }
}

return {
    totalSections: sections.Count,
    totalParagraphs: totalParagraphs,
    preview: preview.slice(0, 30)
};

// 获取文档段落总数及前20段内容预览（修正：遍历Range直接获取段落）
var doc = Application.ActiveDocument;
var totalParagraphs = 0;
var preview = [];
var allText = doc.Content.Text;
var paragraphs = allText.split(/\r\n|\n/);

for (var i = 0; i < Math.min(30, paragraphs.length); i++) {
    var text = paragraphs[i].trim();
    if (text) {
        preview.push({
            index: i + 1,
            text: text,
            hasList: /^\d+[\.\)]\s/.test(text) || /^[a-zA-Z][\.\)]\s/.test(text)
        });
    }
}

return {
    totalParagraphs: paragraphs.length,
    preview: preview
};

// 按中水规范转换全文编号：章节/表/图/公式/参考文献统一为阿拉伯数字格式
var doc = Application.ActiveDocument;
var content = doc.Content.Text;

// 定义转换规则
var rules = [
    // 章节编号：第一章 -> 第1章，1.1 -> 1.1（保持），但统一层级
    {pattern: /第([一二三四五六七八九十]+)章/g, replace: function(m) {
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
        return '第' + numMap[m.replace('第','').replace('章','')] + '章';
    }},
    // 表编号：表一 -> 表1，表一 -> 表1
    {pattern: /表([一二三四五六七八九十]+)/g, replace: function(m) {
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
        var numStr = m.replace('表','');
        return '表' + (numMap[numStr] || numStr);
    }},
    // 图编号：图一 -> 图1
    {pattern: /图([一二三四五六七八九十]+)/g, replace: function(m) {
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
        var numStr = m.replace('图','');
        return '图' + (numMap[numStr] || numStr);
    }},
    // 公式编号：公式1 -> 式(1)，(2-1)保持，但统一前缀
    {pattern: /公式(\d+)/g, replace: '式($1)'},
    // 附录编号：附录一 -> 附录1
    {pattern: /附录([一二三四五六七八九十]+)/g, replace: function(m) {
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
        var numStr = m.replace('附录','');
        return '附录' + (numMap[numStr] || numStr);
    }},
    // 附表编号：附表一 -> 附表1
    {pattern: /附表([一二三四五六七八九十]+)/g, replace: function(m) {
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
        var numStr = m.replace('附表','');
        return '附表' + (numMap[numStr] || numStr);
    }}
];

var result = content;
for (var i = 0; i < rules.length; i++) {
    var rule = rules[i];
    result = result.replace(rule.pattern, rule.replace);
}

return {
    originalLength: content.length,
    newLength: result.length,
    preview: result.substring(0, 2000)
};

// 将转换后的内容写回文档
var doc = Application.ActiveDocument;
var content = doc.Content.Text;

// 定义转换规则（同前）
var rules = [
    {pattern: /第([一二三四五六七八九十]+)章/g, replace: function(m) {
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
        return '第' + numMap[m.replace('第','').replace('章','')] + '章';
    }},
    {pattern: /表([一二三四五六七八九十]+)/g, replace: function(m) {
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
        var numStr = m.replace('表','');
        return '表' + (numMap[numStr] || numStr);
    }},
    {pattern: /图([一二三四五六七八九十]+)/g, replace: function(m) {
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
        var numStr = m.replace('图','');
        return '图' + (numMap[numStr] || numStr);
    }},
    {pattern: /公式(\d+)/g, replace: '式($1)'},
    {pattern: /附录([一二三四五六七八九十]+)/g, replace: function(m) {
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
        var numStr = m.replace('附录','');
        return '附录' + (numMap[numStr] || numStr);
    }},
    {pattern: /附表([一二三四五六七八九十]+)/g, replace: function(m) {
        var numMap = {'一':1,'二':2,'三':3,'四':4,'五':5,'六':6,'七':7,'八':8,'九':9,'十':10};
        var numStr = m.replace('附表','');
        return '附表' + (numMap[numStr] || numStr);
    }}
];

var result = content;
for (var i = 0; i < rules.length; i++) {
    var rule = rules[i];
    result = result.replace(rule.pattern, rule.replace);
}

// 清空原文档并写入新内容
doc.Content.Delete();
doc.Content.InsertAfter(result);

return {
    success: true,
    message: '全文编号已按中水规范转换为阿拉伯数字格式',
    changes: {
        chapters: (content.match(/第[一二三四五六七八九十]+章/g) || []).length,
        tables: (content.match(/表[一二三四五六七八九十]+/g) || []).length,
        figures: (content.match(/图[一二三四五六七八九十]+/g) || []).length,
        formulas: (content.match(/公式\d+/g) || []).length,
        appendices: (content.match(/附录[一二三四五六七八九十]+/g) || []).length
    }
};
